import os
import subprocess
import hashlib
import json

def generate_requirements_txt(requirements_file='requirements.txt'):
    """Generate requirements.txt with hashes for each dependency."""
    try:
        # Install dependencies and generate requirements.txt
        subprocess.run(['pip', 'freeze'], stdout=open(requirements_file, 'w'))
        
        # Add hashes to requirements.txt
        with open(requirements_file, 'r') as f:
            lines = f.readlines()
        
        with open(requirements_file, 'w') as f:
            for line in lines:
                package = line.strip()
                if package:
                    # Calculate hash for the package
                    hash_value = calculate_hash(package)
                    f.write(f"{package} --hash=sha256:{hash_value}\n")
    except Exception as e:
        print(f"Error generating requirements.txt: {e}")

def calculate_hash(package):
    """Calculate the SHA256 hash of the package."""
    try:
        # Use pip to download the package and calculate its hash
        result = subprocess.run(['pip', 'download', package, '--no-deps', '--dest', 'temp_dir'],
                                capture_output=True, text=True)
        
        # Read the downloaded package file
        for file in os.listdir('temp_dir'):
            if file.endswith('.whl') or file.endswith('.tar.gz'):
                with open(os.path.join('temp_dir', file), 'rb') as f:
                    return hashlib.sha256(f.read()).hexdigest()
    finally:
        # Clean up temporary files
        for file in os.listdir('temp_dir'):
            os.remove(os.path.join('temp_dir', file))
        os.rmdir('temp_dir')

def update_dependencies(requirements_file='requirements.txt'):
    """Update dependencies in requirements.txt."""
    try:
        subprocess.run(['pip', 'install', '--upgrade', '-r', requirements_file])
        generate_requirements_txt(requirements_file)
    except Exception as e:
        print(f"Error updating dependencies: {e}")

